ST.xhtml:
G_CAN1_Channel.CheckMessages();
G_CAN2_Channel.CheckMessages();

(* Update callback data *)
IF G_CAN1_Channel.GetLatestError() <> DWORD#0 THEN
	G_CANopen_CAN1_VAR.Callback_Error := EPEC_CANopen.Errors.CallbackError;
ELSE
	G_CANopen_CAN1_VAR.Callback_Error := EPEC_CANopen.Errors.NoError;
END_IF

(* Update protocol data *)
G_CANopen_CAN1.HB_Handler.Update(
	i_Enable := TRUE,
	o_Error => G_CANopen_CAN1_VAR.HB_Error
);
G_CANopen_CAN1.NMT_Handler.Update(
	i_Enable := TRUE,
	o_Error => G_CANopen_CAN1_VAR.NMT_Error
);
G_CANopen_CAN1.SSDO_Handler.Update(
	i_Enable := TRUE,
	o_Error => G_CANopen_CAN1_VAR.SSDO_Error
);
G_CANopen_CAN1.GFC_Handler.Update(
	i_Enable := TRUE,
	o_Error => G_CANopen_CAN1_VAR.GFC_Error
);

G_CANopen_CAN1.OD_ReOrg.Update(o_Ready => , o_Error => G_CANopen_CAN1_VAR.OD_REORG_Error);

G_CANopen_CAN1.SaveODHandler.Update(i_Enable := TRUE,
	o_Ready => G_CANopen_CAN1_VAR.ODSave_OperationReady,
	o_Error => G_CANopen_CAN1_VAR.ODSave_Error);

IF G_CANopen_CAN1_VAR.HB_Error = EPEC_CANopen.Errors.NoError AND
	G_CANopen_CAN1_VAR.NMT_Error = EPEC_CANopen.Errors.NoError AND
	G_CANopen_CAN1_VAR.SSDO_Error = EPEC_CANopen.Errors.NoError AND
	G_CANopen_CAN1_VAR.GFC_Error = EPEC_CANopen.Errors.NoError AND
	G_CANopen_CAN1_VAR.OD_REORG_Error = EPEC_CANopen.Errors.NoError AND
	G_CANopen_CAN1_VAR.ODSave_Error = EPEC_ODSave.SaveODErrors.OD_SAVE_ERR_SUCCESS
THEN
	G_CANopenCan1ProtocolError := FALSE;
ELSE
	G_CANopenCan1ProtocolError := TRUE;
END_IF


(*Check for nmt reset *)
IF G_CANopen_CAN1.NMT.StateChanged THEN
	IF G_CANopen_CAN1.NMT.LastNmtCommand = EPEC_CANopen.NMTCommand.Reset OR 
	   G_CANopen_CAN1.NMT.LastNmtCommand = EPEC_CANopen.NMTCommand.ResetCommunication 
	THEN
		(* If there is NMT reset command for IEC application CANopen device,
			IEC application is started after IEC cycle in execution. *)
		G_RESET_MODULE := TRUE;
	END_IF
END_IF

(* HW diagnostic *) G_HWDiagnostics( i_SupplyVoltage := WORD_TO_UINT(DEV_DSC_SUPPLY_Volt), i_SupplyVoltageHighLimit := G_SupplyVoltageHighLimit, i_SupplyVoltageLowLimit :=G_SupplyVoltageLowLimit, i_Ref5V := WORD_TO_UINT(DEV_DSC_REF_5V), i_Ref5VHighLimit := G_Ref5VHighLimit, i_Ref5VLowLimit := G_Ref5VLowLimit, i_PCBTemperature := DEV_DSC_TEMP_PCB, i_PCBTempHighLimit := G_TempPCBHighLimit, i_PCBTempLowLimit := G_TempPCBLowLimit, i_CPUTemperature := DEV_DSC_TEMP_CPU, i_CPUTempHighLimit := G_TempCPUHighLimit, i_CPUTempLowLimit := G_TempCPULowLimit, i_CycleTimeHighLimit := G_CycleTimeHighLimit, i_AIBiasVoltage := WORD_TO_UINT(DEV_DSC_AI_BIAS_Volt), i_RtcBackupVoltage := WORD_TO_UINT(DEV_DSC_RTC_BACKUP_Volt), i_Voltage12V := 0, i_AIBiasVoltageHighLimit := G_AIBiasVoltageHighLimit, i_AIBiasVoltageLowLimit := G_AIBiasVoltageLowLimit, i_RtcBackupVoltageLowLimit := G_RTCBackupVoltageLowLimit, i_Voltage12VHighLimit := 0, i_Voltage12VLowLimit := 0 );
SUPPLY_Volt := G_HWDiagnostics.o_SupplyVoltage; TEMP_PCB := G_HWDiagnostics.o_PCBTemperature; TEMP_CPU := G_HWDiagnostics.o_CPUTemperature; DEV_DSC_REF_OUT_5V_Enable := REF_OUT_5V_Enable; REF_OUT_5V_OK := (NOT DEV_DSC_REF_OUT_5V_ERROR) AND REF_OUT_5V_Enable; REF_5V := G_HWDiagnostics.o_Ref5V; AIBias_Volt := G_HWDiagnostics.o_AIBiasVoltage; RTCBackup_Volt := G_HWDiagnostics.o_RtcBackupVoltage; Voltage12V := G_HWDiagnostics.o_Voltage12V; ALS_Volt := DEV_DSC_ALS_Volt;
(* DO Sensing *) HWD_DOSensing_68xx(i_MeasuredVoltage := DEV_DSC_DO_DIAG_Volt); DEV_DSC_DO_DIAG_Enable := HWD_DOSensing_68xx.o_Enable; DEV_DSC_DO_DIAG_Selection := HWD_DOSensing_68xx.o_PinSelection;
(*########################################################*) (*This block is created implicit. Don't add own code here.*) (*########################################################*)
(* Diagnostics for CAN interfaces *)
(* CANopen networks management and diagnostics *)
(* System Ok conditions *) G_SystemOk:=NOT(G_HWDiagnostics.o_CPUTemperatureHigh) AND NOT(G_HWDiagnostics.o_CPUTemperatureLow) AND NOT(G_HWDiagnostics.o_PCBTemperatureHigh) AND NOT(G_HWDiagnostics.o_PCBTemperatureLow) AND NOT(G_HWDiagnostics.o_SupplyVoltageHigh) AND NOT(G_HWDiagnostics.o_SupplyVoltageLow) AND NOT(G_HWDiagnostics.o_CycleTimeHigh) AND NOT(G_HWDiagnostics.o_Ref5VHigh) AND NOT(G_HWDiagnostics.o_Ref5VLow) AND NOT(G_HWDiagnostics.o_AIBiasVoltageHigh) AND NOT(G_HWDiagnostics.o_AIBiasVoltageLow);

