(*###########################################################*)

G_CAN1_Channel.InitCAN(i_Channel:= EPEC_6000CANVXD.GVL_6000.CAN1, i_BitRate:=EPEC_CANVXD.BITRATE_1000K, i_Flags:= 0);




G_InitBusReady := TRUE;

(*###########################################################*)
(*This block is created implicit. Don't add own code to here.*)
(*###########################################################*)
/// Call user init until flag is set on.
MainInit();
G_InitEntryReady := MainInit.o_MainInitReady;

IF TRUE = G_InitEntryReady THEN

EPEC_6000INT.GetUserFolder(i_pPath:=ADR(G_UserFolderPath),i_Length:=SIZEOF(G_UserFolderPath));




	{IF defined(SYSTEM_PARAMETERS)}
		(* Read system parameters from flash *)

		SystemParameters.ReadData();

		G_SystemInfo.DeviceName := SystemParameters.o_DeviceName;
		G_SystemInfo.HWVersion := SystemParameters.o_HardwareVersion;
		G_SystemInfo.SWVersion := SystemParameters.o_SoftwareVersion;
		G_SystemInfo.Identity.ProductCode := SystemParameters.o_ProductCode;            (* Type for control unit. *)
		G_SystemInfo.Identity.Revision := SystemParameters.o_RevisionNumber;            (* Revision for control unit *)
		G_SystemInfo.Identity.SerialNumber := SystemParameters.o_SerialNumber;          (* Serial number for control unit *)
		G_SystemInfo.Identity.VendorId := SystemParameters.o_VendorId;                  (* Vendor id which is read from firmware *)

		G_SystemInfo.MACAddress := SystemParameters.o_MAC1;
		G_SystemInfo.EthernetConfiguration :=  SystemParameters.i_Ethernet1;
		G_SystemInfo.CAN1_Comms := SystemParameters.i_CAN1;
		G_SystemInfo.CAN2_Comms := SystemParameters.i_CAN2;
	{END_IF}


END_IF

(*###########################################################*)
(*This block is created implicit. Don't add own code to here.*)
(*###########################################################*)
;

G_NETWORK3_Parameters_CsvFile := Standard.CONCAT(STR1:=G_UserFolderPath, STR2:=G_NETWORK3_Parameters_CsvFile);
G_NETWORK3_Parameters_Count := EPEC_PAR.PARAMETERS_ReadCSV(i_Enable:=TRUE,
	i_File:=G_NETWORK3_Parameters_CsvFile,
	i_ParameterMaxCount:=G_NUMBER_OF_PARAMETERS_NETWORK3,
	i_pCSV:=0,
	i_itfExtraData:=0,
	o_CSVErrorCode=>G_NETWORK3_Parameters_ErrorCode,
	o_CSVErrorLine=>G_NETWORK3_Parameters_ErrorInLine);


G_UI.TimeSyncMethod := EPEC_6000INT.TimeSyncTypes.Manual;


G_InitExitReady:=TRUE;

(*###########################################################*)
(*This block is created implicit. Don't add own code to here.*)
(*###########################################################*)

(* Init system NVRAM *)
SYSTEM_SHM_IEC_GET_AREA(i_pSysSharedMemRegion:= ADR(G_MRAM_Shm));

IF (G_MRAM_Shm.status = TRUE) AND (G_MRAM_Shm.reservedSize >= G_NVRAM_6107_CODE_TEMPLATE_TOTAL) THEN
  (* Init NVRAM pointers*)
  G_NVRAM_6107_StartAddress := G_MRAM_Shm.pStartAddress;
  G_NVRAM_6107_ODParamPointer := G_MRAM_Shm.pStartAddress + G_NVRAM_6107_OD_PARAM_OFFSET;
  G_NVRAM_6107_EventLogPointer := G_MRAM_Shm.pStartAddress + G_NVRAM_6107_EVENTLOG_OFFSET;
  G_NVRAM_6107_UserDataPointer := G_MRAM_Shm.pStartAddress + G_NVRAM_6107_USER_DATA_OFFSET;
  G_NVRAM_6107_GlobEDataPointer := G_MRAM_Shm.pStartAddress + G_NVRAM_6107_GLOBE_DATA_OFFSET;
  G_NVRAM_6107_AzureDataPointer := G_MRAM_Shm.pStartAddress + G_NVRAM_6107_AZURE_DATA_OFFSET;

  (* Init ParameterHandler to use MRAM *)
  G_Common.ParHandler.Init(i_pParamArea:=G_NVRAM_6107_ODParamPointer,
    i_ParamAreaSize:=G_NVRAM_6107_OD_PAR_IMAGE_SIZE ,
    i_Keyword:=G_PARAMHANDLERKEYWORD ,
    i_ParameterMaxDataSize:= G_PARAM_BLOCK_MAX_SIZE);
ELSE
  G_NVRAM_6107_StartAddress := 0;
  G_NVRAM_6107_ODParamPointer := 0;
  G_NVRAM_6107_EventLogPointer := 0;
  G_NVRAM_6107_UserDataPointer := 0;
  G_NVRAM_6107_GlobEDataPointer := 0;
  G_NVRAM_6107_AzureDataPointer := 0;
  G_NVRAM_6107_J1939DM2LogPointer := 0;
  G_NVRAM_MachineTypePointer := 0;
END_IF

(* Init user MRAM *)
IF (G_MRAM_Shm.status = TRUE) AND (0 <> G_NVRAM_6107_UserDataPointer) AND (G_NVRAM_6107_USER_DATA_SIZE >= SIZEOF(UserMramStructure)) THEN
  G_pUserMramStructure := G_NVRAM_6107_UserDataPointer;
  IF G_pUserMramStructure^.UserMRAMTag = 16#AA55AA55 THEN
    G_pUserMramStructure^.UserMRAMdataValid := TRUE;
    G_pUserMramStructure^.UserMRAMinitError := 0;
  ELSE
    G_pUserMramStructure^.UserMRAMdataValid := FALSE;
    G_pUserMramStructure^.UserMRAMTag := 16#AA55AA55;
    G_pUserMramStructure^.UserMRAMinitError := 2;
  END_IF
ELSE
  G_pUserMramStructure := ADR(G_UserMramStructureDefault);
  G_pUserMramStructure^.UserMRAMdataValid := FALSE;
  G_pUserMramStructure^.UserMRAMinitError := 1;
END_IF

G_InitFlashReady:=TRUE;

(*###########################################################*) (*This block is created implicit. Don't add own code to here.*) (*###########################################################*) ; CASE G_InitProtocolsCan1State OF
InitCanProtocolStates.INIT_CANOPEN_PROTOCOLS: (*CAN1 INIT*)
G_CANopen_CAN1.Device.itfCanChannel:=G_CAN1_Channel; (*Connect device to can channel*) G_CANopen_CAN1.Device.NodeID := BYTE#4; G_CANopen_CAN1.NMT.NmtState:=EPEC_CANopen.NMTState.BootUp; (* Set NMT status to BOOTUP *)
(*Initialize OD's data structures*) G_CANopen_CAN1.OD.EntryCount:=SIZEOF(G_CANopen_CAN1.ODEntrys)/SIZEOF(G_CANopen_CAN1.ODEntrys[1]); (*Max entries of given OD(CANopenDeviceODEntrys array)*) G_CANopen_CAN1.OD.InOrder:=FALSE; (*OD isn't in order*) G_CANopen_CAN1.OD.NextFree:=0; (*OD does not have any entries yet*) G_CANopen_CAN1.OD.pODEntry:=ADR(G_CANopen_CAN1.ODEntrys); (*Pointer to OD array*)
(*Define NMT protocol*) G_CANopen_CAN1.Protocols[1].Protocol:=EPEC_CANopen.ProtocolType.NMT; G_CANopen_CAN1.Protocols[1].pData:=ADR(G_CANopen_CAN1.NMT); G_CANopen_CAN1.Protocols[1].itfProtocol:=G_CANopen_CAN1.NMT_Handler; G_CANopen_CAN1.Protocols[1].pError:=ADR(G_CANopen_CAN1_VAR.NMT_Error); G_CANopen_CAN1_VAR.ProtocolAdded[1] := CANopenDeviceAddProtocol( (* Add to protocol stack *) i_pDevice:=ADR(G_CANopen_CAN1.Device), i_pProtocol:=ADR(G_CANopen_CAN1.Protocols[1]), );
(*Initialize NMT protocol*) IF G_CANopen_CAN1_VAR.ProtocolAdded[1] THEN G_CANopen_CAN1.NMT_Handler.Init( i_pDevice := ADR(G_CANopen_CAN1.Device), i_ThisIsMaster := TRUE, i_StartInterval := 1000, i_pMonitoredNodes := ADR(G_CANopen_CAN1.MonitoredNodes), i_NumberOfNodes := 1, i_SimultaneousSlaveConfiguration := FALSE, i_pOdReOrg := ADR(G_CANopen_CAN1.OD_ReOrg), o_Error => G_CANopen_CAN1_VAR.NMT_Error ); ELSE G_CANopen_CAN1_VAR.NMT_Error := EPEC_CANopen.Errors.ProtocolDataMissing; END_IF
(*Define OD protocol*) G_CANopen_CAN1.Protocols[2].Protocol:=EPEC_CANopen.ProtocolType.OD; G_CANopen_CAN1.Protocols[2].pData:=ADR(G_CANopen_CAN1.OD); G_CANopen_CAN1.Protocols[2].pError:=ADR(G_CANopen_CAN1_VAR.OD_Error); G_CANopen_CAN1_VAR.ProtocolAdded[2] := CANopenDeviceAddProtocol( (* Add to protocol stack *) i_pDevice:=ADR(G_CANopen_CAN1.Device), i_pProtocol:=ADR(G_CANopen_CAN1.Protocols[2]), ); IF NOT G_CANopen_CAN1_VAR.ProtocolAdded[2] THEN G_CANopen_CAN1_VAR.OD_Error := EPEC_CANopen.Errors.ProtocolDataMissing; END_IF
(*Define HB protocol - Uses NMT and OD protocol data, thus need to be defined after them. *) G_CANopen_CAN1.HB.HeartBeat.PT := T#200MS; (* HB producer time *) G_CANopen_CAN1.HB.pHBCTimes := ADR(G_CANopen_CAN1_VAR.HBCTimes); (* HB consumer times *)
G_CANopen_CAN1.Protocols[3].Protocol:=EPEC_CANopen.ProtocolType.HB; G_CANopen_CAN1.Protocols[3].pData:=ADR(G_CANopen_CAN1.HB); G_CANopen_CAN1.Protocols[3].itfProtocol:=G_CANopen_CAN1.HB_Handler; G_CANopen_CAN1.Protocols[3].pError:=ADR(G_CANopen_CAN1_VAR.HB_Error); G_CANopen_CAN1_VAR.ProtocolAdded[3] := CANopenDeviceAddProtocol( (* Add to protocol stack *) i_pDevice:=ADR(G_CANopen_CAN1.Device), i_pProtocol:=ADR(G_CANopen_CAN1.Protocols[3]), );
(* Initialize HB protocol *) IF G_CANopen_CAN1_VAR.ProtocolAdded[3] THEN
(* Add monitored nodes *) G_CANopen_CAN1.HB_Handler.AddCallbackToList( i_pDevice := ADR(G_CANopen_CAN1.Device), i_pCallback:=ADR(G_CANopen_CAN1.HBCallbacks[1]), o_Error => G_CANopen_CAN1_VAR.HB_Error ); IF G_CANopen_CAN1_VAR.HB_Error = EPEC_CANopen.Errors.NoError THEN G_CANopen_CAN1.HB_Handler.Init( i_pDevice := ADR(G_CANopen_CAN1.Device), o_Error => G_CANopen_CAN1_VAR.HB_Error ); END_IF ELSE G_CANopen_CAN1_VAR.HB_Error := EPEC_CANopen.Errors.ProtocolDataMissing; END_IF
(*Define SSDO protocol*) G_CANopen_CAN1.Protocols[4].Protocol:=EPEC_CANopen.ProtocolType.SSDO; G_CANopen_CAN1.Protocols[4].pData:=ADR(G_CANopen_CAN1.SSDO); G_CANopen_CAN1.Protocols[4].itfProtocol:=G_CANopen_CAN1.SSDO_Handler; G_CANopen_CAN1.Protocols[4].pError:=ADR(G_CANopen_CAN1_VAR.SSDO_Error); G_CANopen_CAN1_VAR.ProtocolAdded[4] := CANopenDeviceAddProtocol( (* Add to protocol stack *) i_pDevice:=ADR(G_CANopen_CAN1.Device), i_pProtocol:=ADR(G_CANopen_CAN1.Protocols[4]) ); IF G_CANopen_CAN1_VAR.ProtocolAdded[4] THEN G_CANopen_CAN1.SSDO_Handler.Init( i_pDevice := ADR(G_CANopen_CAN1.Device), o_Error => G_CANopen_CAN1_VAR.SSDO_Error ); ELSE G_CANopen_CAN1_VAR.SSDO_Error := EPEC_CANopen.Errors.ProtocolDataMissing; END_IF
(*Define GFC protocol*) G_CANopen_CAN1.Protocols[5].Protocol:=EPEC_CANopen.ProtocolType.GFC; G_CANopen_CAN1.Protocols[5].pData:=ADR(G_CANopen_CAN1.GFC); G_CANopen_CAN1.Protocols[5].itfProtocol:=G_CANopen_CAN1.GFC_Handler; G_CANopen_CAN1.Protocols[5].pError:=ADR(G_CANopen_CAN1_VAR.GFC_Error); G_CANopen_CAN1_VAR.ProtocolAdded[5] := CANopenDeviceAddProtocol( (* Add to protocol stack *) i_pDevice:=ADR(G_CANopen_CAN1.Device), i_pProtocol:=ADR(G_CANopen_CAN1.Protocols[5]) ); IF G_CANopen_CAN1_VAR.ProtocolAdded[5] THEN G_CANopen_CAN1.GFC_Handler.Init( i_pDevice := ADR(G_CANopen_CAN1.Device), i_pStatus:=ADR(G_CANopen_CAN1_VAR.GFC_Status), o_Error => G_CANopen_CAN1_VAR.GFC_Error ); ELSE G_CANopen_CAN1_VAR.GFC_Error := EPEC_CANopen.Errors.ProtocolDataMissing; END_IF
