(* 16#1008 Manufacturer device name *) IF G_CANopen_CAN1_VAR.OD_Error = EPEC_CANopen.Errors.NoError THEN G_CANopen_CAN1_VAR.OD_Error := CANopenODAddLine( i_pOD := ADR(G_CANopen_CAN1.OD),(*Address of Object dictionary where index will be added*) i_Index := G_CANOPEN_ODINDEX_MF_DEVICE_NAME, i_ObjectCode := EPEC_CANopen.ObjectCode.OD_VAR,(*Type of index*) i_NumOfSubids := USINT#0,(*Number of subindexes*) i_TypeSpec := EPEC_CANopen.DataType.Deftype_STRING,(*Index datatype, either user defined or standard CiA 301*) i_ObjectAccess := G_CANOPEN_OD_ACCESS_NOWRITE OR G_CANOPEN_OD_ACCESS_SUB0NOWRITE, i_Sub0data := USINT#0,(*Value of subindex0 in array or (def)struct*) i_pIndexData := ADR(G_SystemInfo.DeviceName), i_itfSDOHandler := DWORD#0 ); END_IF
(* 16#100A Manufacturer software version *) IF G_CANopen_CAN1_VAR.OD_Error = EPEC_CANopen.Errors.NoError THEN G_CANopen_CAN1_VAR.OD_Error := CANopenODAddLine( i_pOD := ADR(G_CANopen_CAN1.OD),(*Address of Object dictionary where index will be added*) i_Index := G_CANOPEN_ODINDEX_MF_SW_VERSION, i_ObjectCode := EPEC_CANopen.ObjectCode.OD_VAR,(*Type of index*) i_NumOfSubids := USINT#0,(*Number of subindexes*) i_TypeSpec := EPEC_CANopen.DataType.Deftype_STRING,(*Index datatype, either user defined or standard CiA 301*) i_ObjectAccess := G_CANOPEN_OD_ACCESS_NOWRITE OR G_CANOPEN_OD_ACCESS_SUB0NOWRITE, i_Sub0data := USINT#0,(*Value of subindex0 in array or (def)struct*) i_pIndexData := ADR(G_SystemInfo.SWVersion), i_itfSDOHandler := DWORD#0 ); END_IF
(* 16#1018 Vendor ID *) IF G_CANopen_CAN1_VAR.OD_Error = EPEC_CANopen.Errors.NoError THEN G_CANopen_CAN1_VAR.OD_Error := CANopenODAddLine( i_pOD := ADR(G_CANopen_CAN1.OD),(*Address of Object dictionary where index will be added*) i_index := G_CANOPEN_ODINDEX_IDENTITY_OBJECT, i_ObjectCode := EPEC_CANopen.ObjectCode.OD_ARRAY, (*Type of index*) i_NumOfSubids := USINT#4,(*Number of subindexes*) i_TypeSpec := EPEC_CANopen.DataType.Deftype_UNSIGNED32,(*Index of 16-bit deftype*) i_ObjectAccess := G_CANOPEN_OD_ACCESS_NOWRITE OR G_CANOPEN_OD_ACCESS_SUB0NOWRITE, i_sub0data := USINT#4,(*Value of subindex0 in array or (def)struct*) i_pIndexData := ADR(G_SystemInfo.Identity), i_itfSDOHandler := DWORD#0 ); END_IF (* 16#2030 CodesysVersion *) IF G_CANopen_CAN1_VAR.OD_Error = EPEC_CANopen.Errors.NoError THEN G_CANopen_CAN1_VAR.OD_Error := CANopenODAddLine( i_pOD := ADR(G_CANopen_CAN1.OD),(*Address of Object dictionary where index will be added*) i_index := 16#2030, i_ObjectCode := EPEC_CANopen.ObjectCode.OD_ARRAY, (*Type of index*) i_NumOfSubids := USINT#1,(*Number of subindexes*) i_TypeSpec := EPEC_CANopen.DataType.Deftype_UNSIGNED32,(*Index of 16-bit deftype*) i_ObjectAccess := G_CANOPEN_OD_ACCESS_READWRITE OR G_CANOPEN_OD_ACCESS_SUB0NOWRITE, i_sub0data := USINT#1,(*Value of subindex0 in array or (def)struct*) i_pIndexData := ADR(G_SystemInfo.ToolsVersion), i_itfSDOHandler := DWORD#0 ); END_IF
