(* 16#2129 PDO Dummy Variable Index *) IF G_CANopen_CAN1_VAR.OD_Error = EPEC_CANopen.Errors.NoError THEN G_CANopen_CAN1_VAR.OD_Error := CANopenODAddLine( i_pOD := ADR(G_CANopen_CAN1.OD),(*Address of Object dictionary where index will be added*) i_Index := 16#2129, i_ObjectCode := EPEC_CANopen.ObjectCode.OD_VAR,(*Type of index*) i_NumOfSubids := USINT#0,(*Number of subindexes*) i_TypeSpec := EPEC_CANopen.DataType.Deftype_UNSIGNED8,(*Index datatype, either user defined or standard CiA 301*) i_ObjectAccess := G_CANOPEN_OD_ACCESS_READWRITE, i_Sub0data := USINT#0,(*Value of subindex0 in array or (def)struct*) i_pIndexData := ADR(G_CAN1_VAR.CAN1_RPDO_DUMMY), i_itfSDOHandler := DWORD#0 ); END_IF
(* 16#2130 Application version *) IF G_CANopen_CAN1_VAR.OD_Error = EPEC_CANopen.Errors.NoError THEN G_CANopen_CAN1_VAR.OD_Error := CANopenODAddLine( i_pOD := ADR(G_CANopen_CAN1.OD),(*Address of Object dictionary where index will be added*) i_index := 16#2130, i_ObjectCode := EPEC_CANopen.ObjectCode.OD_ARRAY, (*Type of index*) i_NumOfSubids := USINT#10,(*Number of subindexes*) i_TypeSpec := EPEC_CANopen.DataType.Deftype_STRING,(*Index of 16-bit deftype*) i_ObjectAccess := G_CANOPEN_OD_ACCESS_NOWRITE OR G_CANOPEN_OD_ACCESS_SUB0NOWRITE, i_sub0data := USINT#10,(*Value of subindex0 in array or (def)struct*) i_pIndexData := ADR(G_SystemInfo.SoftwareInformation), i_itfSDOHandler := DWORD#0 ); END_IF
(* 16#2140 MAC address byte 1 *) IF G_CANopen_CAN1_VAR.OD_Error = EPEC_CANopen.Errors.NoError THEN G_CANopen_CAN1_VAR.OD_Error := CANopenODAddLine( i_pOD := ADR(G_CANopen_CAN1.OD),(*Address of Object dictionary where index will be added*) i_index := 16#2140, i_ObjectCode := EPEC_CANopen.ObjectCode.OD_ARRAY, (*Type of index*) i_NumOfSubids := USINT#6,(*Number of subindexes*) i_TypeSpec := EPEC_CANopen.DataType.Deftype_UNSIGNED8,(*Index of 16-bit deftype*) i_ObjectAccess := G_CANOPEN_OD_ACCESS_NOWRITE OR G_CANOPEN_OD_ACCESS_SUB0NOWRITE, i_sub0data := USINT#6,(*Value of subindex0 in array or (def)struct*) i_pIndexData := ADR(G_SystemInfo.MACAddress), i_itfSDOHandler := DWORD#0 ); END_IF
(* 16#2141 Ethernet enabled/disabled *) IF G_CANopen_CAN1_VAR.OD_Error = EPEC_CANopen.Errors.NoError THEN G_CANopen_CAN1_VAR.OD_Error := CANopenODAddLine( i_pOD := ADR(G_CANopen_CAN1.OD),(*Address of Object dictionary where index will be added*) i_index := 16#2141, i_ObjectCode := EPEC_CANopen.ObjectCode.OD_ARRAY, (*Type of index*) i_NumOfSubids := USINT#50,(*Number of subindexes*) i_TypeSpec := EPEC_CANopen.DataType.Deftype_UNSIGNED8,(*Index of 16-bit deftype*) i_ObjectAccess := G_CANOPEN_OD_ACCESS_READWRITE OR G_CANOPEN_OD_ACCESS_SUB0NOWRITE, i_sub0data := USINT#50,(*Value of subindex0 in array or (def)struct*) i_pIndexData := ADR(G_SystemInfo.EthernetConfiguration), i_itfSDOHandler := DWORD#0 ); END_IF
(* 16#2150 Codesys communication enabled *) IF G_CANopen_CAN1_VAR.OD_Error = EPEC_CANopen.Errors.NoError THEN G_CANopen_CAN1_VAR.OD_Error := CANopenODAddLine( i_pOD := ADR(G_CANopen_CAN1.OD),(*Address of Object dictionary where index will be added*) i_index := 16#2150, i_ObjectCode := EPEC_CANopen.ObjectCode.OD_ARRAY, (*Type of index*) i_NumOfSubids := USINT#10,(*Number of subindexes*) i_TypeSpec := EPEC_CANopen.DataType.Deftype_UNSIGNED16,(*Index of 16-bit deftype*) i_ObjectAccess := G_CANOPEN_OD_ACCESS_READWRITE OR G_CANOPEN_OD_ACCESS_SUB0NOWRITE, i_sub0data := USINT#10,(*Value of subindex0 in array or (def)struct*) i_pIndexData := ADR(G_SystemInfo.CAN1_Comms), i_itfSDOHandler := DWORD#0 ); END_IF
(* 16#2151 Codesys communication enabled *) IF G_CANopen_CAN1_VAR.OD_Error = EPEC_CANopen.Errors.NoError THEN G_CANopen_CAN1_VAR.OD_Error := CANopenODAddLine( i_pOD := ADR(G_CANopen_CAN1.OD),(*Address of Object dictionary where index will be added*) i_index := 16#2151, i_ObjectCode := EPEC_CANopen.ObjectCode.OD_ARRAY, (*Type of index*) i_NumOfSubids := USINT#10,(*Number of subindexes*) i_TypeSpec := EPEC_CANopen.DataType.Deftype_UNSIGNED16,(*Index of 16-bit deftype*) i_ObjectAccess := G_CANOPEN_OD_ACCESS_READWRITE OR G_CANOPEN_OD_ACCESS_SUB0NOWRITE, i_sub0data := USINT#10,(*Value of subindex0 in array or (def)struct*) i_pIndexData := ADR(G_SystemInfo.CAN2_Comms), i_itfSDOHandler := DWORD#0 ); END_IF
(* 16#2131 Parameter CSV unique ID *) IF G_CANopen_CAN1_VAR.OD_Error = EPEC_CANopen.Errors.NoError THEN G_CANopen_CAN1_VAR.OD_Error := CANopenODAddLine( i_pOD := ADR(G_CANopen_CAN1.OD),(*Address of Object dictionary where index will be added*) i_Index := 16#2131, i_ObjectCode := EPEC_CANopen.ObjectCode.OD_VAR,(*Type of index*) i_NumOfSubids := USINT#0,(*Number of subindexes*) i_TypeSpec := EPEC_CANopen.DataType.Deftype_UNSIGNED16,(*Index datatype, either user defined or standard CiA 301*) i_ObjectAccess := G_CANOPEN_OD_ACCESS_NOWRITE OR G_CANOPEN_OD_ACCESS_SUB0NOWRITE, i_Sub0data := USINT#0,(*Value of subindex0 in array or (def)struct*) i_pIndexData := ADR(G_CAN1_VAR.Parameter_CSV_unique_ID1), i_itfSDOHandler := DWORD#0 ); END_IF
G_InitProtocolsCan1State := InitCanProtocolStates.INIT_CANOPEN_PDO;
InitCanProtocolStates.INIT_CANOPEN_PDO:
G_InitProtocolsCan1State := InitCanProtocolStates.INIT_CANOPEN_OD_SAVE;
InitCanProtocolStates.INIT_CANOPEN_OD_SAVE:
(*Initialize OD save*) G_CANopen_CAN1.SaveSubData1010h.pSaveSigns := ADR(G_CANopen_CAN1_VAR.SaveSigns1010[0]); G_CANopen_CAN1.SaveSubData1010h.NumOfEntrys := 4; G_CANopen_CAN1.SaveSubData1010h.pSaveIndexData := ADR(G_CANopen_CAN1.SaveData[0]); G_CANopen_CAN1.SaveData[3].itfSaveAll := G_CANopen_CAN1.SaveAll; G_CANopen_CAN1.SaveData[3].itfDeleteAll := G_CANopen_CAN1.DeleteAll; G_CANopen_CAN1.OD.pAdditionalData := ADR(G_CANopen_CAN1.SaveSubData1010h);
