G_CANopen_CAN1.OD_ReOrg.Init(i_pOD := ADR(G_CANopen_CAN1.OD), i_NumOfODIndexPerCycle := 50); G_CANopen_CAN1.OD_ReOrg.Start();
G_InitProtocolsCan1State := InitCanProtocolStates.INIT_CANOPEN_OD_REORG;
InitCanProtocolStates.INIT_CANOPEN_OD_REORG:
G_CANopen_CAN1.OD_ReOrg.Update(o_Ready => G_CANopen_CAN1_VAR.OdReOrgReady, o_Error => G_CANopen_CAN1_VAR.OD_REORG_Error);
IF G_CANopen_CAN1_VAR.OdReOrgReady THEN (* Check all protocol init status flags *) IF G_CANopen_CAN1_VAR.NMT_Error = EPEC_CANopen.Errors.NoError AND G_CANopen_CAN1_VAR.SSDO_Error = EPEC_CANopen.Errors.NoError AND G_CANopen_CAN1_VAR.OD_Error = EPEC_CANopen.Errors.NoError AND G_CANopen_CAN1_VAR.HB_Error = EPEC_CANopen.Errors.NoError AND G_CANopen_CAN1_VAR.CSDO_Error = EPEC_CANopen.Errors.NoError AND G_CANopen_CAN1_VAR.GFC_Error = EPEC_CANopen.Errors.NoError AND G_CANopen_CAN1_VAR.OD_REORG_Error = EPEC_CANopen.Errors.NoError THEN G_InitCANopenCan1Error := FALSE; (* No errors in protocol inits *) ELSE G_InitCANopenCan1Error := TRUE; END_IF G_InitProtocolsCan1State := InitCanProtocolStates.INIT_CANOPEN_OD_REORG_READY; END_IF
InitCanProtocolStates.INIT_CANOPEN_OD_REORG_READY: G_InitProtocolsCan1State := INIT_INITIALIZE_OD_PARAMS;
INIT_INITIALIZE_OD_PARAMS: G_CANopen_CAN1.SaveODHandler.InitializeODParams(i_Enable:=TRUE, o_Ready=>G_CANopen_CAN1_VAR.ODParametersInitialized, o_Error=>G_CANopen_CAN1_VAR.ODSave_Error);
IF G_CANopen_CAN1_VAR.ODParametersInitialized THEN G_InitProtocolsCan1State := InitCanProtocolStates.INIT_INITIALIZE_OD_PARAMS_READY; END_IF
INIT_INITIALIZE_OD_PARAMS_READY:
G_InitProtocolsCan1State := InitCanProtocolStates.INIT_J1939;
InitCanProtocolStates.INIT_J1939:
G_InitProtocolsCan1State := InitCanProtocolStates.INIT_PROTOCOLS_DONE;
InitCanProtocolStates.INIT_PROTOCOLS_DONE: G_InitProtocolsCan1Ready := TRUE;
END_CASE

