KL15_X1_6 := DEV_DSC_KL15;

(* tag EPEC_OUT_OTHER *)


(* If reset flag is on make reset. For 6107 runtime is restarted. *)
IF G_RESET_MODULE THEN
    BOOT_APPLICATION_KILL_RTS();
END_IF

{IF defined(SYSTEM_PARAMETERS)}

IF G_CommsParamCounterRestoreCmdOld <> G_SaveOD_RestoreCommsCounter THEN
    (* Restore command given trough CANopen *)
    G_CommsParamCounterRestoreCmdOld := G_SaveOD_RestoreCommsCounter;
    SystemParameters.RestoreDefaultData();
    G_SystemInfo.EthernetConfiguration := SystemParameters.i_Ethernet1;
    G_SystemInfo.CAN1_Comms := SystemParameters.i_CAN1;
    G_SystemInfo.CAN2_Comms := SystemParameters.i_CAN2;
END_IF

IF G_CommsParamCounterSaveCmdOld <> G_SaveOD_SaveCommsCounter THEN
    (* Save command given trough CANopen *)
    G_CommsParamCounterSaveCmdOld := G_SaveOD_SaveCommsCounter;
    SystemParameters.i_Ethernet1 := G_SystemInfo.EthernetConfiguration;
    SystemParameters.i_CAN1 := G_SystemInfo.CAN1_Comms;
    SystemParameters.i_CAN2 := G_SystemInfo.CAN2_Comms;
    SystemParameters.WriteData();
END_IF


{END_IF}

IF G_Common.ParHandler.o_ParamAreaLocked THEN
	G_Common.ParHandler.DisableChanges(i_DisableChanges := FALSE);
